#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, B;
        scanf("%d %d", &A, &B);
        int limak = 0, bob = 0, turn = 1;
        while (1) {
            if (turn == 1) {
                if (limak + turn > A) {
                    printf("Bob\n");
                    break;
                }
                limak += turn;
            } else {
                if (bob + turn > B) {
                    printf("Limak\n");
                    break;
                }
                bob += turn;
            }
            turn++;
            if (turn % 2 == 0) turn++;
        }
    }
    return 0;
}

